-- Database Engineer Roadmap seed.
-- Idempotent seed. Safe to rerun.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource_map;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- Clean previous copy of this specific roadmap only.
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title = 'Database Engineer Roadmap'
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title = 'Database Engineer Roadmap'
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title = 'Database Engineer Roadmap'
);

DELETE FROM public.roadmap
WHERE title = 'Database Engineer Roadmap';

VALUES (
    'Database Engineer',
    'database-engineer',
    'A practical roadmap for CS students learning relational modeling, SQL performance, PostgreSQL administration, reliability, migrations, security, and database platform operations.',
    'Database',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'database-engineer'
), inserted_roadmap AS (
SELECT career_role_id, 'Database Engineer Roadmap', 'A practical roadmap for CS students learning relational modeling, SQL performance, PostgreSQL administration, reliability, migrations, security, and database platform operations.', 'public'
FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
SELECT roadmap_id, 1, 'published', 'Database Engineer Roadmap v1', 'A curated static roadmap for CS students with phases, topics, checkpoints, projects, direct skills, resources, and validation-safe persisted mappings.', 410, 'TB', 'manual', now()
FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Local skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;


('database-engineer-architecture', 'Database Architecture', 'Architecture & System Design', 'Designing database boundaries, dependencies, replication patterns, reliability tradeoffs, and operational responsibilities.'),
('database-engineer-backend', 'Backend Data Access Patterns', 'Backend', 'Understanding how service behavior, transactions, query load, and connection patterns affect database design and operations.'),
('database-engineer-cybersecurity', 'Database Security Controls', 'Cybersecurity', 'Applying access control, encryption, audit evidence, risk reduction, and operational response for database systems.'),
('database-engineer-data-engineering', 'Database Support for Data Engineering', 'Data Engineering', 'Supporting pipeline-aware schemas, data quality checks, integration workloads, and analytical handoff requirements.'),
('database-engineer-database-design', 'Operational Database Design', 'Database', 'Designing schemas, constraints, indexes, and data access patterns that remain maintainable in production.'),
('database-engineer-database-normalization', 'Database Normalization', 'Database', 'Applying normal forms, dependency analysis, integrity constraints, and denormalization tradeoffs in relational models.'),
('database-engineer-performance-testing', 'Database Performance Testing', 'Software Quality', 'Designing repeatable workload tests, measuring latency and throughput, and comparing tuning changes with evidence.'),
('database-engineer-query-planning', 'Database Query Planning', 'Database', 'Reading query plans, identifying expensive operations, and validating query improvements with measured execution behavior.'),
('database-engineer-technical-writing', 'Database Operations Documentation', 'Career & Communication', 'Writing runbooks, migration notes, recovery steps, tuning decisions, and operational handoff documentation.'),
('database-engineer-transactions-and-isolation', 'Database Transactions and Isolation', 'Database', 'Managing transaction scope, isolation levels, lock behavior, anomalies, and consistency tradeoffs.'),
('database-engineer-indexing', 'Database Indexing', 'Database', 'Designing indexes around access patterns, query plans, write costs, and production performance constraints.'),
('database-engineer-replication', 'Replication for Database Operations', 'Database', 'Managing replication behavior, lag, failover risks, and operational recovery paths for production databases.'),
('database-engineer-automation', 'Database Operations Automation', 'DevOps & Platform', 'Automating repeatable database administration tasks with scripts, runbooks, change safety, and operational checks.');

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    category = EXCLUDED.category,
    description = EXCLUDED.description,
    is_active = true,
    updated_at = now();

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;

SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM (
    SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

DROP TABLE IF EXISTS seed_resource_map;
CREATE TEMP TABLE seed_resource_map AS
SELECT sr.resource_key, lr.learning_resource_id
FROM seed_resource sr
JOIN (
    SELECT DISTINCT ON (url) learning_resource_id, url
    FROM public.learning_resource
    ORDER BY url, created_at DESC, learning_resource_id
) lr ON lr.url = sr.url;

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    layout_role text NOT NULL,
    estimated_hours int,
    difficulty_level text,
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;


SELECT sn.node_id, m.roadmap_version_id, parent.node_id, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.order_index, sn.layout_role, sn.estimated_hours, sn.difficulty_level, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (
    node_key text NOT NULL,
    skill_slug text NOT NULL,
    PRIMARY KEY (node_key, skill_slug)
) ON COMMIT DROP;


