INSERT INTO seed_node
(node_key, parent_key, order_index, node_type, checkpoint_type, selection_type, required_count, title, description, layout_role, estimated_hours, difficulty_level, metadata, is_required, is_trackable, learning_outcomes, completion_criteria)
VALUES
('ph-database-engineering-role-and-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Database Engineering Role and Foundations', 'This stage builds the database engineering role and foundations layer of the Database Engineer path.', 'trunk', NULL, NULL, '{"role":"database-engineer","nodeKey":"ph-database-engineering-role-and-foundations"}'::jsonb, true, false, '["Database Engineering Role and Foundations"]'::jsonb, '["Required child nodes in this phase are completed."]'::jsonb),
('database-engineer-responsibilities', 'grp-database-engineering-role-and-foundations-foundations', 1, 'topic', NULL, NULL, NULL, 'Database Engineer Responsibilities', 'Apply database engineer responsibilities to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'side', 4, 'beginner', '{"role":"database-engineer","nodeKey":"database-engineer-responsibilities"}'::jsonb, true, true, '["Explain database engineer responsibilities using concrete examples.","Apply database engineer responsibilities to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates database engineer responsibilities with reviewable evidence."]'::jsonb),
('data-integrity-and-operational-safety', 'grp-database-engineering-role-and-foundations-foundations', 2, 'topic', NULL, NULL, NULL, 'Data Integrity and Operational Safety', 'Apply data integrity and operational safety to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'choice', 4, 'beginner', '{"role":"database-engineer","nodeKey":"data-integrity-and-operational-safety"}'::jsonb, true, true, '["Explain data integrity and operational safety using concrete examples.","Apply data integrity and operational safety to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates data integrity and operational safety with reviewable evidence."]'::jsonb),
('relational-vs-non-relational-systems', 'grp-database-engineering-role-and-foundations-foundations', 3, 'topic', NULL, NULL, NULL, 'Relational vs Non-Relational Systems', 'Compare relational and non-relational systems by schema flexibility, consistency needs, query patterns, scaling model, and operational complexity.', 'choice', 4, 'beginner', '{"role":"database-engineer","nodeKey":"relational-vs-non-relational-systems"}'::jsonb, true, true, '["Match common workload needs to relational or non-relational storage choices.", "Explain tradeoffs without treating one model as universally better."]'::jsonb, '["A storage-choice comparison explains data model, access pattern, consistency, and operations tradeoffs."]'::jsonb),
